import base64
import pickle
import json
from datetime import datetime
from typing import Any, Dict, List
import logging

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def process_batch_job(job_data: Dict[str, Any]) -> Dict[str, Any]:
    """Process a single batch job"""
    job_id = job_data.get('job_id', 'unknown')
    job_type = job_data.get('job_type', 'default')
    payload = job_data.get('payload', {})
    
    logger.info(f"Processing job {job_id} of type {job_type}")
    
    result = {
        'job_id': job_id,
        'job_type': job_type,
        'status': 'completed',
        'processed_at': datetime.utcnow().isoformat(),
        'result': None
    }
    
    try:
        if job_type == 'data_aggregation':
            result['result'] = aggregate_data(payload)
        elif job_type == 'data_transformation':
            result['result'] = transform_data(payload)
        elif job_type == 'computation':
            result['result'] = perform_computation(payload)
        else:
            result['result'] = generic_processing(payload)
            
        logger.info(f"Job {job_id} completed successfully")
        
    except Exception as e:
        logger.error(f"Error processing job {job_id}: {str(e)}")
        result['status'] = 'failed'
        result['error'] = str(e)
    
    return result


def aggregate_data(payload: Dict[str, Any]) -> Dict[str, Any]:
    """Aggregate data from payload"""
    data_items = payload.get('items', [])
    
    total = sum(item.get('value', 0) for item in data_items if isinstance(item, dict))
    count = len(data_items)
    average = total / count if count > 0 else 0
    
    return {
        'total': total,
        'count': count,
        'average': average
    }


def transform_data(payload: Dict[str, Any]) -> List[Dict[str, Any]]:
    """Transform data according to rules"""
    data_items = payload.get('items', [])
    transformation_rule = payload.get('rule', 'uppercase')
    
    transformed = []
    for item in data_items:
        if isinstance(item, dict):
            transformed_item = item.copy()
            if transformation_rule == 'uppercase' and 'text' in item:
                transformed_item['text'] = item['text'].upper()
            elif transformation_rule == 'multiply' and 'value' in item:
                multiplier = payload.get('multiplier', 2)
                transformed_item['value'] = item['value'] * multiplier
            transformed.append(transformed_item)
    
    return transformed


def perform_computation(payload: Dict[str, Any]) -> Any:
    """Perform computational tasks"""
    operation = payload.get('operation', 'sum')
    values = payload.get('values', [])
    
    if operation == 'sum':
        return sum(values)
    elif operation == 'product':
        result = 1
        for v in values:
            result *= v
        return result
    elif operation == 'matrix_multiply' and 'matrix_a' in payload and 'matrix_b' in payload:
        matrix_a = payload['matrix_a']
        matrix_b = payload['matrix_b']
        return matrix_multiply(matrix_a, matrix_b)
    else:
        return None


def matrix_multiply(a: List[List[float]], b: List[List[float]]) -> List[List[float]]:
    """Simple matrix multiplication"""
    rows_a = len(a)
    cols_a = len(a[0]) if a else 0
    cols_b = len(b[0]) if b else 0
    
    result = [[0 for _ in range(cols_b)] for _ in range(rows_a)]
    
    for i in range(rows_a):
        for j in range(cols_b):
            for k in range(cols_a):
                result[i][j] += a[i][k] * b[k][j]
    
    return result


def generic_processing(payload: Dict[str, Any]) -> Dict[str, Any]:
    """Generic processing for unknown job types"""
    return {
        'processed': True,
        'payload_keys': list(payload.keys()),
        'payload_size': len(str(payload))
    }


def process_pubsub_message(event, context):
    """
    Cloud Function triggered by Pub/Sub.
    Processes serialized Python objects from task queue.
    
    Args:
        event (dict): The dictionary with data specific to this type of event.
        context (google.cloud.functions.Context): Metadata of triggering event.
    """
    try:
        if 'data' not in event:
            logger.error("No data field in event")
            return
        
        message_data = base64.b64decode(event['data'])
        
        job_data = pickle.loads(message_data)
        
        logger.info(f"Deserialized job data: {type(job_data)}")
        
        if isinstance(job_data, dict):
            result = process_batch_job(job_data)
        elif isinstance(job_data, list):
            results = []
            for job in job_data:
                if isinstance(job, dict):
                    results.append(process_batch_job(job))
            result = {'batch_results': results, 'total_jobs': len(results)}
        else:
            result = {
                'status': 'completed',
                'data_type': str(type(job_data)),
                'data': str(job_data)
            }
        
        logger.info(f"Processing result: {json.dumps(result, default=str)}")
        
        publish_result(result, event.get('attributes', {}))
        
    except pickle.UnpicklingError as e:
        logger.error(f"Failed to unpickle message data: {str(e)}")
    except Exception as e:
        logger.error(f"Error processing message: {str(e)}")
        raise


def publish_result(result: Dict[str, Any], attributes: Dict[str, str]):
    """Publish processing result (placeholder for actual implementation)"""
    logger.info(f"Publishing result with attributes: {attributes}")
    logger.info(f"Result: {json.dumps(result, default=str)}")


def pubsub_handler(event, context):
    """Main entry point for Cloud Function"""
    return process_pubsub_message(event, context)